import{c as t,Q as a,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"TheSequence — 2026-04-28","description":"","frontmatter":{"title":"TheSequence — 2026-04-28","date":"2026-04-28T00:00:00.000Z","source":"TheSequence","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-28-thesequence.md","filePath":"research/ai-news/2026-04/2026-04-28-thesequence.md","lastUpdated":1779894392000}'),o={name:"research/ai-news/2026-04/2026-04-28-thesequence.md"};function s(h,e,c,i,l,u){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="🔢-thesequence-—-2026-04-28" tabindex="-1">🔢 TheSequence — 2026-04-28 <a class="header-anchor" href="#🔢-thesequence-—-2026-04-28" aria-label="Permalink to &quot;🔢 TheSequence — 2026-04-28&quot;">​</a></h1><blockquote><p>165k+ 訂閱；ML / 企業 AI 應用週報，Jesus Rodriguez 主筆 來源：<a href="https://thesequence.substack.com/feed" target="_blank" rel="noreferrer">TheSequence</a></p></blockquote><hr><h2 id="the-sequence-knowledge-850-the-unexpected-comeback-of-rnns" tabindex="-1"><a href="https://thesequence.substack.com/p/the-sequence-knowledge-850-the-unexpected" target="_blank" rel="noreferrer">The Sequence Knowledge #850: The Unexpected Comeback of RNNs</a> <a class="header-anchor" href="#the-sequence-knowledge-850-the-unexpected-comeback-of-rnns" aria-label="Permalink to &quot;[The Sequence Knowledge #850: The Unexpected Comeback of RNNs](https://thesequence.substack.com/p/the-sequence-knowledge-850-the-unexpected)&quot;">​</a></h2><p><em>🔢 TheSequence | 2026-04-28</em></p><p>💡 AI Concept of the Day: The Unexpected Comeback of RNNs</p><p>If you were building sequence models circa 2015, your mental model of the world was entirely shaped by Recurrent Neural Networks (RNNs). There was a deep, architectural elegance to them. You feed the network a token, it updates a fixed-size hidden state, and it throws the token away. During inference, the memory footprint was beautifully constant—an $O(1)$ operation that could run efficiently on almost any hardware.</p><p>Then came 2017. “Attention Is All You Need” dropped, and the entire AI ecosystem pivoted. We traded the elegance of the RNN for the brute-force parallelizability of the Transformer. The Transformer won the hardware lottery because it allowed us to map the entire sequence onto a GPU grid and train it all at once. But we made a devil’s bargain: the Key-Value (KV) cache.</p><p>In a Transformer, the model must explicitly hold the high-dimensional representations of every previous token in memory to generate the next one. This is an O(N^2) operation. As we push models to 100K, 1M, and now multi-million token context windows, the compute graph becomes mathematically offensive. We are burning vast amounts of high-bandwidth memory simply doing memory reads.</p><p>This is why, if you watch the arXiv firehose closely right now, you will notice a massive vibe shift. We are witnessing the comeback of the RNN. But this is not a nostalgic return to the classic Long Short-Term Memory (LSTM) networks of the 2010s. The new generation of RNNs features larger states, data-dependent gating, and LLM-era training recipes. They are matching Transformer perplexity at scale, but keeping that sweet $O(1)$ inference cost.</p><p>Here is a look at the architectures driving the recurrent renaissance.</p><p><a href="https://thesequence.substack.com/p/the-sequence-knowledge-850-the-unexpected" target="_blank" rel="noreferrer"> Read more </a></p><hr>',13)])])}const m=t(o,[["render",s]]);export{p as __pageData,m as default};
